const input = $input.item.json.body;

const courseOverview = input.course_overview || '';
let courseOverviewText = '';
if (courseOverview) {
  try {
    const ov = typeof courseOverview === 'string' ? JSON.parse(courseOverview) : courseOverview;
    courseOverviewText = `已有课程概览如下，请严格基于此概览生成教案，保持故事情境、教学目标、产出任务完全一致：\n标题：${ov.courseTitle || ''}\n情境：${ov.overallContext || ''}\n语言目标：词汇=${ov.languageGoals?.vocabulary || ''}，句型=${ov.languageGoals?.grammar || ''}\nSEL目标：${ov.selGoals || ''}\nPERMA目标：${ov.permaGoals || ''}\n产出任务：${ov.finalTask || ''}`;
  } catch (e) {
    courseOverviewText = courseOverview;
  }
}

return {
  age: input.age || "7-9岁",
  duration: input.duration || "60分钟",
  scale: input.scale || "≤ 8人",
  title: input.title || "未命名课件",
  vocabulary: (input.vocabulary && input.vocabulary.length > 0) 
              ? input.vocabulary.join(', ') 
              : "请根据主题推荐词汇",
  grammar: (input.grammar && input.grammar.length > 0) 
           ? input.grammar.join(', ') 
           : "请根据主题推荐句型",
  skills_text: input.skills ? input.skills.join(' + ') : "",
  paths_text: input.paths ? input.paths.join(' + ') : "",
  theme: input.theme || "",
  requirements: input.requirements || "",
  course_overview: courseOverview,
  course_overview_text: courseOverviewText
};
